// src/App.js
import React, { useState, useEffect } from 'react';

function App() {
    const [apiStatus, setApiStatus] = useState('Checking...');
    const [sensorStatus, setSensorStatus] = useState(null);

    useEffect(() => {
        fetch('http://localhost:3001/')
            .then(res => res.json())
            .then(data => {
                setApiStatus('✅ Connected to backend');
                console.log('Backend:', data);
            })
            .catch(err => {
                setApiStatus('❌ Cannot connect to backend');
                console.error(err);
            });

        fetch('http://localhost:3001/api/sensor/status')
            .then(res => res.json())
            .then(data => setSensorStatus(data))
            .catch(err => console.error(err));
    }, []);

    return (
        <div style={{ padding: '20px', fontFamily: 'Arial' }}>
            <h1>🏥 E-Health System</h1>
            <p>Backend: {apiStatus}</p>
            {sensorStatus && (
                <p>Sensor: {sensorStatus.connected ? '✅ Connected' : '❌ Disconnected'} (Port: {sensorStatus.port})</p>
            )}
            <div style={{ marginTop: '20px' }}>
                <button onClick={() => window.open('http://localhost:3001/', '_blank')}>
                    Test Backend API
                </button>
            </div>
        </div>
    );
}

export default App;
